    period_ema = inputs.get('period_ema', 20)
    period_atr = inputs.get('period_atr', 20)
    multiplier = inputs.get('multiplier', 2.0)

    def exponential_moving_average(data, periods):
        if not data or periods <= 0 or len(data) < periods:
            return []
        ema_values = [sum(data[:periods]) / periods]
        multiplier_ema = 2 / (periods + 1)
        for price in data[periods:]:
            ema_values.append((price - ema_values[-1]) * multiplier_ema + ema_values[-1])
        return ema_values

    def average_true_range(data, periods):
        if not data or periods <= 0 or len(data) < 2:
            return []
        true_ranges = [abs(data[i] - data[i - 1]) for i in range(1, len(data))]
        if len(true_ranges) < periods:
            return []
        atr_values = [sum(true_ranges[:periods]) / periods]
        for i in range(periods, len(true_ranges)):
            atr_values.append((atr_values[-1] * (periods - 1) + true_ranges[i]) / periods)
        return atr_values
    ema_series = exponential_moving_average(prices, period_ema)
    atr_series = average_true_range(prices, period_atr)
    min_len = min(len(ema_series), len(atr_series))
    if min_len == 0:
        return None
    ema_aligned = ema_series[-min_len:]
    atr_aligned = atr_series[-min_len:]
    upper_band_series = [m + multiplier * a for m, a in zip(ema_aligned, atr_aligned)]
    if upper_band_series:
        return round(upper_band_series[-1], 2)
    else:
        return None

