def calculate_simple_moving_average_series(prices: list, period: int) -> list:
    if not (isinstance(prices, list) and all((isinstance(p, (int, float)) for p in prices))):
        raise ValueError('Prices must be a list of numbers.')
    if not (isinstance(period, int) and period > 0 and (period <= len(prices))):
        raise ValueError('Period must be a positive integer and not exceed the length of the prices list.')
    sma_series = []
    for i in range(len(prices) - period + 1):
        sma_series.append(sum(prices[i:i + period]) / period)
    return sma_series

def compute(inputs):
    prices = inputs['prices']
    period = inputs['period']
    sma_index = inputs['sma_index']
    all_smas = calculate_simple_moving_average_series(prices, period)
    if not (isinstance(sma_index, int) and 0 <= sma_index < len(all_smas)):
        raise IndexError(f'SMA index {sma_index} is out of bounds for the calculated SMA series of length {len(all_smas)}.')
    result = all_smas[sma_index]
    return round(result, 2)

